function pyramidPattern(n) {
  if (!Number.isInteger(n) || n <= 0) return '';

  const rows = [];
  for (let i = 1; i <= n; i += 1) {
    const spaces = ' '.repeat(n - i);
    const stars = '*'.repeat(2 * i - 1);
    rows.push(spaces + stars);
  }

  return rows.join('\n');
}

function deepOmit(value, keysToOmit) {
