    if (node && typeof node === 'object') {
      const out = {};
      for (const [key, val] of Object.entries(node)) {
        if (blocked.has(key)) continue;
        out[key] = walk(val);
      }
      return out;
    }

    return node;
  }

  return walk(value);
}

function debounce(fn, wait = 0) {
  let timer = null;
  let lastArgs;
  let lastThis;

  function invoke() {
    const result = fn.apply(lastThis, lastArgs);
    lastArgs = undefined;
    lastThis = undefined;
    return result;
  }

  function debounced(...args) {
    lastArgs = args;
    lastThis = this;

    if (timer) clearTimeout(timer);
    timer = setTimeout(() => {
      timer = null;
      invoke();
    }, wait);
  }

  debounced.cancel = function () {
    if (timer) clearTimeout(timer);
    timer = null;
    lastArgs = undefined;
    lastThis = undefined;
  };

  debounced.flush = function () {
    if (!timer) return;
    clearTimeout(timer);
    timer = null;
    return invoke();
  };

  return debounced;
}

function findWords(board, words) {
  if (!board.length || !board[0].length || !words.length) return [];

  const root = {};
  for (const word of words) {
    let node = root;
    for (const ch of word) {
      if (!node[ch]) node[ch] = {};
      node = node[ch];
    }
    node.word = word;
  }

  const rows = board.length;
  const cols = board[0].length;
  const found = [];
  const dirs = [
    [1, 0],
    [-1, 0],
    [0, 1],
    [0, -1]
  ];

  function dfs(r, c, parent) {
    const ch = board[r][c];
    const node = parent[ch];
    if (!node) return;

    if (node.word) {
      found.push(node.word);
      node.word = null;
    }

    board[r][c] = '#';

    for (const [dr, dc] of dirs) {
      const nr = r + dr;
      const nc = c + dc;
      if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
      if (board[nr][nc] === '#') continue;
      dfs(nr, nc, node);
    }

    board[r][c] = ch;

    if (Object.keys(node).length === 0) {
      delete parent[ch];
    }
  }

  for (let r = 0; r < rows; r += 1) {
    for (let c = 0; c < cols; c += 1) {
      dfs(r, c, root);
    }
  }

  return found;
}

function combinationSum(candidates, target) {
  const nums = [...new Set(candidates)].sort((a, b) => a - b);
  const result = [];
  const path = [];

  function backtrack(start, remaining) {
    if (remaining === 0) {
      result.push([...path]);
      return;
    }

    for (let i = start; i < nums.length; i += 1) {
      const value = nums[i];
      if (value > remaining) break;

      path.push(value);
      backtrack(i, remaining - value);
      path.pop();
    }
  }

  backtrack(0, target);
  return result;
}

