  const graph = Array.from({ length: n }, () => []);
  for (const [u, v] of edges) {
    graph[u].push(v);
    graph[v].push(u);
  }

  const visited = new Array(n).fill(false);

  function dfs(node, parent) {
    visited[node] = true;

    for (const next of graph[node]) {
      if (!visited[next]) {
        if (dfs(next, node)) return true;
