}

class EventEmitter {
  constructor() {
    this.events = new Map();
  }

  on(event, handler) {
    if (!this.events.has(event)) {
      this.events.set(event, new Set());
    }
    this.events.get(event).add(handler);
    return () => this.off(event, handler);
  }

  off(event, handler) {
    const set = this.events.get(event);
    if (!set) return;
    set.delete(handler);
    if (set.size === 0) this.events.delete(event);
  }

  once(event, handler) {
    const off = this.on(event, (...args) => {
      off();
      handler(...args);
    });
    return off;
  }

  emit(event, ...args) {
    const set = this.events.get(event);
    if (!set) return false;

    for (const handler of [...set]) {
      handler(...args);
    }
    return true;
  }

  listenerCount(event) {
    return this.events.get(event)?.size || 0;
  }
}

function searchInSortedMatrix(matrix, target) {
  if (!matrix.length || !matrix[0].length) return false;

  const rows = matrix.length;
  const cols = matrix[0].length;
  let left = 0;
  let right = rows * cols - 1;

  while (left <= right) {
    const mid = left + ((right - left) >> 1);
    const r = Math.floor(mid / cols);
    const c = mid % cols;
    const value = matrix[r][c];

    if (value === target) return true;
    if (value < target) left = mid + 1;
    else right = mid - 1;
  }

  return false;
}

function mergeArrayById(...arrays) {
  const map = new Map();

  for (const arr of arrays) {
    for (const item of arr) {
      if (!item || item.id === undefined || item.id === null) continue;

      const prev = map.get(item.id) || {};
      map.set(item.id, { ...prev, ...item });
    }
  }

  return Array.from(map.values());
}

function memoize(fn, resolver) {
  const cache = new Map();

  return function memoized(...args) {
    const key = resolver ? resolver.apply(this, args) : JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key);
    }

    const value = fn.apply(this, args);
    cache.set(key, value);
    return value;
  };
}

function shortestDistanceFromSource(n, edges, source) {
  const graph = Array.from({ length: n }, () => []);

  for (const [u, v] of edges) {
    graph[u].push(v);
    graph[v].push(u);
  }

  const dist = new Array(n).fill(-1);
  const queue = [source];
  dist[source] = 0;

  for (let head = 0; head < queue.length; head += 1) {
    const node = queue[head];

    for (const next of graph[node]) {
      if (dist[next] !== -1) continue;
      dist[next] = dist[node] + 1;
      queue.push(next);
    }
  }

  return dist;
}

function lengthOfLongestSubstring(s) {
  const lastSeen = new Map();
  let left = 0;
  let best = 0;

  for (let right = 0; right < s.length; right += 1) {
    const ch = s[right];

    if (lastSeen.has(ch) && lastSeen.get(ch) >= left) {
      left = lastSeen.get(ch) + 1;
    }

    lastSeen.set(ch, right);
    best = Math.max(best, right - left + 1);
  }

  return best;
}

function objectAssign(target, ...sources) {
  if (target === null || target === undefined) {
    throw new TypeError('Cannot convert undefined or null to object');
  }

  const to = Object(target);

  for (const source of sources) {
    if (source === null || source === undefined) continue;

    const from = Object(source);
    for (const key of Reflect.ownKeys(from)) {
      if (Object.prototype.propertyIsEnumerable.call(from, key)) {
        to[key] = from[key];
      }
    }
  }

  return to;
}

function orangesRotting(grid) {
  const rows = grid.length;
  const cols = grid[0].length;
  const queue = [];
  let fresh = 0;

  for (let r = 0; r < rows; r += 1) {
    for (let c = 0; c < cols; c += 1) {
      if (grid[r][c] === 2) {
        queue.push([r, c, 0]);
      } else if (grid[r][c] === 1) {
        fresh += 1;
      }
    }
  }

  const dirs = [
    [1, 0],
    [-1, 0],
    [0, 1],
    [0, -1]
  ];

  let minutes = 0;

  for (let head = 0; head < queue.length; head += 1) {
    const [r, c, time] = queue[head];
    minutes = Math.max(minutes, time);

    for (const [dr, dc] of dirs) {
      const nr = r + dr;
      const nc = c + dc;

      if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
      if (grid[nr][nc] !== 1) continue;

      grid[nr][nc] = 2;
      fresh -= 1;
      queue.push([nr, nc, time + 1]);
    }
  }

  return fresh === 0 ? minutes : -1;
}

function compressStringWithLimitedRepetition(str, maxRun = Infinity) {
  if (typeof str !== 'string' || str.length === 0) return '';
  if (maxRun <= 0) throw new RangeError('maxRun must be > 0');

  let out = '';
  let i = 0;

  while (i < str.length) {
    const ch = str[i];
    let j = i;

    while (j < str.length && str[j] === ch) {
      j += 1;
    }

    let count = j - i;

    while (count > maxRun) {
      out += ch + String(maxRun);
      count -= maxRun;
    }

    out += ch;
    if (count > 1) out += String(count);

    i = j;
  }

  return out;
}
